{
  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "A Dseefma pahr wiſchmahm / tas Salamanam pee- verr.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Lai wiſch mahnti ſkubpſta ar fatwas Muttes Skahpstifchannu / jo fatwas Mih- lestibas irr jo mihligas neka Wihs.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Ka tawn fardu Eſti fa-obſt warr/ taws Wahrdg irr weena tsgahsta Eſte/ tapehz uihle tewi tahs Meitahs.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Welz mann/ tad tezzeſtim mehs tew pakkat/ tas Kehnifsch wed mann fatwds Rambardg/ mehs lihgſinoſtimees un preeza- ſtimees eekſch tewis/ mehs pee- minneſtim tawas Mihlestibas wairak neka Wihnu/ tee Rahmi uihle tewi.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Es etinu melna/ bet mihliga/ (Juhs Jerufalemes Meitas/) itt ka tahs Kedara Zeltis/ ka Salamanas Gardines.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Ne uſluhkojeet manni/ ka es pamella efmu/ jo ta Saule irr manu apspeeduft / mannas Mahfes Behrni irr prett manu apſkattuschees/ tee irr mann ee- zelhuſcht var Sargataju to Wilh-\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Stahſti mar na Dwehfele miſlo ni/ kur tu guldijees io kapehz ſtaigafch klahtu Waigu pee gannameim Pulkee\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Ja tu ſewi ne wiſtu ſtaiftaka ſtarp tad eij ahra uſ to dahm/ un ganni ta nus pee to Gann tkeem.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Es lihdſinaju t Draudſene ar teem S Warauſ Ratteem.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Tawi Waigt Sprahdſes/ taws Ra lu Apkaktg.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Mehs darrifsim ta Sprahdſes ar Sudra bukeem.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Kamehr tas ar ſawu Aptampſchan dohd manna Nardu ſawu Smarfchu.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Mans Drau weens Mirres Puſf\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Mans T weens Reſtars\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Redſi na Draudſer ſta/ tawas loschu\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
